 public function __construct(private readonly FieldServiceRepositoryContract$repo,private readonly FieldServiceValidator$validator,private readonly FieldOperationValidator$operations,private readonly StockService$stock,private readonly ConnectionService$connections,private readonly CustomerService$customers,private readonly BillingScheduleRepositoryContract$billingSchedules,private readonly AuditLoggerContract$audit){}
 public function dashboard():array{return$this->repo->dashboard();} public function list(FieldServiceListFilters$f):array{return$this->repo->listOrders($f);} public function get(int$id):array{$o=$this->repo->findOrder($id)??throw new NotFoundException('Work order not found.');$o['materials']=$this->repo->materials($id);$o['visits']=$this->repo->visits($id);$o['logs']=$this->repo->logs($id);$o['timeline']=$this->repo->timeline($id);return$o;}
